var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>계획 1 — 환기구를 통해 탈출한다.</color>","JPN":"<color=#ffd34c>計画1—換気口から脱出する。</color>","ENG":"<color=#ffd34c>Plan 1 – Escape through the vents.</color>","TWN":"<color=#ffd34c>計畫1——利用通風口逃跑。</color>"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"으윽! 실키, 허리가 낀 것 같아요! 도와 주세요!","JPN":"ううっ！　シルキー、腰が引っかかってしまったようです！　助けてください！","ENG":"Ngh! Sylkie, I think I'm stuck! Please help me!","TWN":"呃啊！思琪，我的腰好像卡住了！快幫幫我！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"끄응…! 끄으으읏…!","JPN":"ううん……！　うううんっ……！","ENG":"Ngh...! Errgh...!!","TWN":"咳呃……！咳呃呃呃……！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"죄, 죄송해요. 부학회장님…. 제 키로는 손이 안 닿아요.","JPN":"も、申し訳ありません。副学会長様……私の背では手が届きません。","ENG":"I-I'm sorry, ma'am... But I'm too short to reach you.","TWN":"對…對不起，副學會長……我太矮了手碰不到。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>실패 원인 — 환기구가 예상보다 작음.</color>","JPN":"<color=#ffd34c>失敗の原因—換気口が予想より狭い。</color>","ENG":"<color=#ffd34c>Cause of failure – The vents were smaller than expected.</color>","TWN":"<color=#ffd34c>失敗原因——通風口比想像中小。</color>"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>계획 2 — 꾀병을 부린다.</color>","JPN":"<color=#ffd34c>計画2—仮病を使う。</color>","ENG":"<color=#ffd34c>Plan 2 – Fake an illness.</color>","TWN":"<color=#ffd34c>計畫2——裝病。</color>"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_A","text":{"KOREA":"내장기관을 비롯한 신체 어디에도 유의미한 문제는 없었습니다.","JPN":"内臓器官をはじめ、身体のどこにも問題はありませんでした。","ENG":"We examined every part of your body, including your intestines, and found no evidence of significant problems.","TWN":"包括內臟器官在內的身體所有部位，都沒有任何明顯問題。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOCTOR_NPC_ESPR2_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_NPC_ESPR2_B","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_B","text":{"KOREA":"부학회장님의 요양을 위해 학회장님께서 의료에 관련된 아티팩트를 보내 주셨습니다.","JPN":"副学会長の療養のためにと、学会長が医療関連のアーティファクトを送ってくださいました。","ENG":"The President even sent over a medical Artifact for your recovery.","TWN":"為了讓副學會長安心休養，學會長送來了和醫療有關的人造神器。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOCTOR_NPC_ESPR2_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_NPC_ESPR2_B","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_B","text":{"KOREA":"어떤 병이라도 치료할 수 있을 테니 걱정하지 마십시오.","JPN":"どんな病気でも治療できますので、ご安心を。","ENG":"It will allow us to treat any illness, so please don't worry.","TWN":"可以治好任何疾病，所以你不用擔心。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOCTOR_NPC_ESPR2_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_NPC_ESPR2_B","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"됐으니까 다들 썩 나가요!","JPN":"わかりましたから、皆さんさっさと出て行ってください！","ENG":"I have had enough! Get out!!","TWN":"算了，你們都出去吧！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>실패 원인 — 시설 내에 의료 자원을 보유 중.</color>","JPN":"<color=#ffd34c>失敗の原因—施設内に医療チームを保有中。</color>","ENG":"<color=#ffd34c>Cause of failure – Medical resources are available within the facility.</color>","TWN":"<color=#ffd34c>失敗原因——設施內配有醫療資源。</color>"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>계획 3 — 스푼으로 벽을 판다.</color>","JPN":"<color=#ffd34c>計画3—スプーンで壁を掘る。</color>","ENG":"<color=#ffd34c>Plan 3 – Dig a tunnel in the wall with a spoon.</color>","TWN":"<color=#ffd34c>計畫3——用湯匙在牆上挖洞。</color>"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"그래서 내 방 벽에 구멍을 뚫어서 무너뜨렸다고?","JPN":"それで、アタシの部屋の壁に穴を開けて崩したんだって？","ENG":"So, you made a hole in the wall of my room and knocked it down?","TWN":"所以，你是想在我房間的牆上挖洞，然後把牆弄塌嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L24_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"당신이 제 옆방에 사는지 몰랐으니까 그랬죠!","JPN":"あなたが私の隣の部屋だとは知りませんでしたわ！","ENG":"How was I supposed to know you were right next to me?!","TWN":"我根本就不知道你住在我隔壁！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L25_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"지금 화내는 거야? 난 너 때문에 개인 공간도 없어졌다고!","JPN":"なに怒ってるの？　アタシはあんたのせいで自分の部屋もなくなったってのに！","ENG":"Oh, you're mad? Because of you, I now don't have any personal space!","TWN":"你現在是在對我發火嗎？因為你，我連自己的私人空間都沒有了！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L26_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"부학회장만 아니었으면 이걸 진짜! 이익~!","JPN":"副学会長でさえなければ！　この女！　キーッ！","ENG":"If you were not Vice President, then I'd...! Errgh!","TWN":"你要不是副學會長，我真是！吼～！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"아야야야! 숙녀 머리채를 잡아당기면 어떡해요!","JPN":"いたたた！　淑女の髪を引っ張るなんて！","ENG":"H-hey! How dare you pull on a lady's hair?!","TWN":"啊啊啊啊！你怎麼可以扯淑女的頭髮！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그러니까 당장 여기서 내보내 달라고요!","JPN":"ですから、今すぐここから出しなさいというのです！","ENG":"I demand to be released this instant!","TWN":"所以說快點放我出去！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"아파아앗! 머리 잡아당기지 마!","JPN":"痛っ！　髪引っ張らないでよ！","ENG":"Ouch! Quit pulling on my hair!","TWN":"好痛喔！不要扯我的頭髮！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"두 분 다 그만하세요! 그러다 머리 벗겨져요!","JPN":"お二人とも、おやめください！　ハゲになってしまいますよ！","ENG":"Please stop it, the both of you!! Or you'll both go bald!","TWN":"兩位快住手！再扯下去，快要禿頭了！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>계획 4 — 실패.</color>","JPN":"<color=#ffd34c>計画4—失敗。</color>","ENG":"<color=#ffd34c>Plan 4 – Failed.</color>","TWN":"<color=#ffd34c>計畫4——失敗。</color>"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>계획 5 실패. 계획 6 실패, 실패, 실패……</color>","JPN":"<color=#ffd34c>計画5、失敗。計画6、失敗。失敗、失敗……</color>","ENG":"<color=#ffd34c>Plan 5 – Failed. Plan 6 – Failed... Failed... Failed...</color>","TWN":"<color=#ffd34c>計畫5失敗，計畫6失敗，失敗，失敗……</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"다음 계획은……. 별똥별에게 소원을 빈다.","JPN":"次の計画は……流れ星に願いをかける。","ENG":"My next plan is to... wish upon the stars.","TWN":"下個計畫是……向流星許願。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"아니. 아니야. 어쩌면 이건 전부 날 미신에 빠지게 하려는 에델의 함정일지도 몰라.","JPN":"いえ、そうではなくて。もしかしたらあれもこれも私に迷信を信じさせようとするエデルの罠かもしれないわ。","ENG":"No. This all might be a trap made by Edel to make me believe in some superstition.","TWN":"不…不行。說不定這些都是艾瑟兒想要讓我沉迷於迷信的陷阱。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L42_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"다음 계획으로 넘어가자. 반드시 내 힘으로 이 감옥을 벗어나고 말겠어.","JPN":"次の計画に移るのよ。必ずやこの手でこの牢獄を抜け出してみせるんだから。","ENG":"I must move on to my next plan. I will get out of the prison on my own.","TWN":"換下個計畫吧。我一定要靠自己的力量逃出這個監獄。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"부학회장님, 고민은 건강에 좋지 않아요.","JPN":"副学会長様、悩みはお体に障ります。","ENG":"Vice President, worrying too much is not good for your health.","TWN":"副學會長，煩惱有害健康。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L45_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"오늘은 홍차를 우려 봤어요. 한 모금 드시면서 마음을 가라앉히시는 게 어떨까요?","JPN":"今日は紅茶を淹れてみました。お飲みになりながら落ち着かれてはいかがですか？","ENG":"Today, I made some tea. Would you like some to relax your nerves?","TWN":"今天我泡了紅茶。你喝一口，平復一下心情怎麼樣？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그렇게 초조해 보였나요?","JPN":"そんなに焦ってるように見えましたか？","ENG":"Do I look that nervous?","TWN":"我看起來那麼焦慮嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"네. 벌써 몇 시간째 공책만 뚫어져라 들여다보고 계셨으니까요.","JPN":"はい。もう何時間もノートをだけを穴のあくほど眺めておいででした。","ENG":"Yes. You've been starting at that notebook for hours.","TWN":"是的，你已經盯著筆記本看了好幾個小時了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L48_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그렇게나 오래요? 시계가 없으니까 신경도 못 썼네요.","JPN":"そんなに長い間？　時計がないから気付きませんでしたわ。","ENG":"Has it been that long? Without a clock, my sense of time is practically gone.","TWN":"那麼久了嗎？因為沒有時鐘，我都沒怎麼注意。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L49_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"시간이 지나면 분명 나가게 해 줄 거예요. 너무 걱정 마세요.","JPN":"時間が経てばきっと出してくださるはずです。あまりご心配なさらずに。","ENG":"I'm sure they'll let us leave eventually. So don't worry too much.","TWN":"時間到了，他們肯定會讓你出去的。你別太擔心了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_LAUGH"}}}},{"id":"L50_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"하지만 제가 자리를 비운 동안 학회는 계속해서 온갖 나쁜 짓을 저지르고 다니겠죠.","JPN":"ですが、私が席を外している間も学会はあらゆる悪さをし続けているに違いありませんわ。","ENG":"But while I am absent, the Society will continue to do all sorts of heinous activities.","TWN":"可是我不在的這段時間，學會應該會繼續做各種壞事吧。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_LAUGH"}}}},{"id":"L5_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"……저 소리, 오늘은 더 유난스럽네요.","JPN":"……あの音、今日は一段と響きますわね。","ENG":"That sound... It is rather different today.","TWN":"……那個聲音，今天特別吵鬧呢。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"역시 인체 실험 아닐까? 혹시나 살아 있는 사람들이 대상이라면……","JPN":"やはり人体実験ではないですの？　生きている人間が対象だとしたら……","ENG":"Could it be some kind of human experimentation? And if it is done on a living person...?","TWN":"不會是人體實驗吧？難道是用活人……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"부학회장님은 학회를 무척 싫어하시는 것 같아요.","JPN":"副学会長様は学会のことがとてもお嫌いのようですね。","ENG":"You seem to despise the Society, don't you?","TWN":"副學會長好像真的很討厭學會。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"아, 죄송해요. 부학회장님. 제가 너무 주제 넘게 굴었어요.","JPN":"あ、失礼しました。副学会長様。出過ぎたことを申し上げました。","ENG":"Oh, my apologies, ma'am. I overstepped.","TWN":"啊，對不起，副學會長。是我多嘴了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"아뇨. 정확해요. 저는 학회를 싫어합니다.","JPN":"いいえ。的を得ています。私は学会など嫌いですわ。","ENG":"No, you are correct. I do despise the Society.","TWN":"沒有，你說得對。我很討厭學會。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"학회의, 그리고 저희 가문의 역사를 파헤칠수록 구역질나는 사실들만 나왔으니까요.","JPN":"学会の、そしてマクレディー家の歴史を掘り返すたびにおぞましい事実ばかりが出てくるのですから。","ENG":"The more I look into the Society and my family's past, the more I am disgusted by it.","TWN":"因為越是深挖學會還有我們家族的歷史，就會發現更多令人作嘔的事。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"하지만 영지에 사는 분들은 학회를 무척 자랑스러워하시는 걸요.","JPN":"でも領地の住民たちは学会をとても誇りに思っていますよ。","ENG":"But the residents are really proud of the Society.","TWN":"可是在領地生活的人們，都為學會感到自豪。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"계몽주의 운동처럼 오랫동안 사람들을 무지에서 벗어나게 해 주셨다면서요.","JPN":"啓蒙運動のように、長い時間をかけて人々を無知から解放してくれたのだそうです。","ENG":"Similar to the Enlightenment movement, they've been saving us from the depths of ignorance.","TWN":"聽說就像啟蒙主義運動一樣，學會讓人們擺脫了長期以來的無知。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"설령 그렇다고 한들, 분별 없이 지식만 추종하는 근간이 달라지진 않아요.","JPN":"仮にそうだとしても、見境もなく知識だけに追従する学会の根幹が変わるわけではありません。","ENG":"Even if that were true, their underlying principle of pursuing only knowledge indiscriminately remains the same.","TWN":"即便如此，盲目追求知識的核心也不會改變。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"결국 호수에게 던져 줄 먹잇감이나 찾아다니는 광인들에 불과합니다.","JPN":"結局のところ、湖に投げ込む餌を求めて探し回る狂人の群れに過ぎないのです。","ENG":"They are nothing but maniacs who search for prey to give to the Lake.","TWN":"說到底，他們不過是到處尋找獵物，然後扔進湖水的一群瘋子。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"부학회장님…….","JPN":"副学会長様……","ENG":"Vice President...","TWN":"副學會長……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"제가 여기 갇혀 있는 동안 밖에서는 자기들 마음대로 온갖 짓들을 저지르고 있을 거예요.","JPN":"私がここに閉じ込められている間、外では好き勝手にあらゆることをしでかしていることでしょう。","ENG":"While I am locked up here, they will be wreaking havoc out there.","TWN":"我被關在這裡的時候，他們肯定會在外面任意妄為，做各種壞事。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"호수가 얼마나 위험한 건지, 자기들이 무슨 끔찍한 짓을 저지르고 다니는 건지 설명해도 들어먹질 않으니까요.","JPN":"湖がどれほど危険なものなのか、自分たちがどれほど恐ろしいことをしているのか、説明をしても理解できないのですから。","ENG":"No matter how much I try to explain how dangerous the Lake is or how terrible their actions are, they refuse to listen.","TWN":"就算和他們說過湖水有多危險，他們的行為到底有多可怕，他們也聽不進去。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"도대체 왜 다들 헛된 망상에서 빠져나오지 못하는 거죠?","JPN":"どうして皆さん、つまらない妄想から抜け出せないのでしょうか。","ENG":"Why do they insist on keeping up with this delusion?","TWN":"為什麼大家就不願脫離妄想呢？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"애초에 주민들을 영지로 데리고 온 것도—","JPN":"そもそも住民を領地に連れてきたのも……","ENG":"Bringing in residents to the estate in the first place wa–","TWN":"最初帶居民們來領地也是——"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"—방금 들었어요?","JPN":"……今の音、聞きましたか？","ENG":"–Did you hear that?","TWN":"——你聽到剛才的動靜了嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_RIFLE_FIRE_02"},{"id":"L24_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"네. 총소리였어요. 혹시 외지인이 침입한 것 아닐까요?","JPN":"はい。銃声でした。領地外の人でも侵入したのでしょうか？","ENG":"Yes, that was a gun. Are we being invaded by outlanders?","TWN":"聽到了，是槍聲。不會是有外地人入侵吧？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"실키, 지금 같은 상황에 이유는 중요하지 않습니다.","JPN":"シルキー、今の状況において理由は重要ではありません。","ENG":"Sylkie, the reason is not of importance in situations like this.","TWN":"思琪，現在這種情況下，原因不重要。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"부학회장님, 갑자기 왜 그렇게 문에 바짝 붙으세요?","JPN":"副学会長様、どうして突然ドアにぴったりくっついていらっしゃるのですか？","ENG":"Vice President, why are you hugging the wall like that?","TWN":"副學會長，你為什麼突然緊貼到門上？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"쉿. 복도에서 무슨 소리가 나는지 확인하려는 거예요.","JPN":"しっ。廊下から聞こえる音を確認しているのです。","ENG":"Shh! I am trying to hear what is going on in the hallway.","TWN":"噓，我想聽聽走廊上有什麼動靜。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L31_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"방음 처리가 되어 있긴 하지만, 귀를 대고 있으면 뭔가 들릴지도 몰라요.","JPN":"防音加工がされていても、耳を当てていれば何か聞こえるかもしれません。","ENG":"Even if it is soundproofed, I might be able to hear something if I put my ear against it.","TWN":"雖然門做了隔音處理，但是把耳朵貼上去，說不定能聽到什麼。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"으음, 평소랑 다르게 무척 소란스러운걸요.","JPN":"ううむ、いつもと違って異常に騒がしいですわ。","ENG":"Hmm... I hear a ruckus. How odd.","TWN":"呃嗯，和平時不一樣，很吵。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_CROWD_NOISE_05"},{"id":"L34_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"쿵쿵거리는 소리도 계속 들려요. 공사라도 하는 건가?","JPN":"ドン、ドンという音もずっと聞こえます。工事でもしているのかしら。","ENG":"There is something thumping. Are you doing construction work out there?","TWN":"還一直有咚咚的響聲。是在施工嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L36_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"꺄아악!?","JPN":"きゃああっ！？","ENG":"Kyaah!","TWN":"啊啊啊！？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_B","text":{"KOREA":"컥……. 으윽…….","JPN":"ぐはっ……ううっ……","ENG":"Kuh...! Ngh...","TWN":"咳……呃咳……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_B","text":{"KOREA":"부학회장님……. 절대, 나가시면…….","JPN":"副学会長様……絶対、外に出ては……","ENG":"Vice President... you mustn't leave...","TWN":"副學會長……絕對，不可以出去……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"하, 학회원 분이세요. 벽을 부수고 굴러 들어오셨는데… 살아 계실까요?","JPN":"が、学会員の方です。壁を壊して転がりこんでこられましたが……生きているのでしょうか？","ENG":"I-it's a Society member. He went flying through a wall... Do you think he's still alive?","TWN":"是…是學會成員。好像是撞破牆後滾進來的……還活著嗎？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_BATTLEFIELD"},{"id":"L43_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"아뇨. 이미 틀렸어요. 맥박이 잡히지 않습니다.","JPN":"いいえ。死んでいます。脈が感じられないわ。","ENG":"No, it is too late. I cannot feel a pulse on him.","TWN":"不，來不及了，沒有脈搏了。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"세상에……. 매일 뱅쇼가 식지 않게 신경 써 주신 분이었는데.","JPN":"そんな……毎日ホットワインが冷めないように気遣ってくださった方でしたのに。","ENG":"Oh dear... He was the one who made sure the vin chaud didn't get cold every day.","TWN":"天啊……這個人每天都會送熱紅酒過來呢。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"애도는 나중에 표하세요, 실키. 지금이 기회입니다.","JPN":"哀悼は後です、シルキー。今がチャンスですわ。","ENG":"Sylkie, please express your condolences later. Now is our chance.","TWN":"以後再表示哀悼吧，思琪。現在是個機會。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"네? 기회라니요?","JPN":"はい？　チャンス？","ENG":"Sorry? Our chance?","TWN":"什麼？機會？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그야 당연히 탈출할 기회죠. 싸우느라 정신이 없어서 우리가 사라졌는지도 모를 거예요.","JPN":"当然、脱出のチャンスという意味ですわ。戦うことに手一杯で私たちがいなくなったことにも気付かないはずです。","ENG":"Our chance to escape. They will be so busy dealing with the fighting that they will not even notice we are gone.","TWN":"當然是逃跑的機會了。他們正忙著打架，應該不會有人發現我們溜走。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"기다리세요, 부학회장님! 밖은 너무 위험해요!","JPN":"お待ちください、副学会長様！　外は危険すぎます！","ENG":"Hold on, ma'am! It's dangerous out there!","TWN":"等等，副學會長！外面太危險了！"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"위험은 영지에 돌아왔을 때 겪을 만큼 겪어서 익숙합니다!","JPN":"危険は領地に戻ってきたときから存分に経験したので、もう慣れていますわ！","ENG":"I have been exposed to enough danger ever since I arrived at the estate that it no longer frightens me!","TWN":"在我回到領地的過程中，就已經經歷過很多危險了，所以對我不算什麼！"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"어디 해칠 테면 해쳐 보라죠!","JPN":"やれるものなら、やってみろというのです！","ENG":"Let it do its worst!","TWN":"誰想傷我，就儘管試試看吧！"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CHASER_NPC_ESPR2_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHASER_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"……아.","JPN":"……あ。","ENG":"...Ah.","TWN":"……啊。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CHASER_NPC_ESPR2_NULL","text":{"KOREA":"<color=#ff3636>찾았. 다.</color>","JPN":"<color=#ff3636>見ツケ、タ。</color>","ENG":"<color=#ff3636>I Found. You.</color>","TWN":"<color=#ff3636>找·到·你·了。</color>"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHASER_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_PAWN_DAMAGE_DOWN"},{"id":"L8_1","type":"dialog","speaker":"CHASER_NPC_ESPR2_NULL","text":{"KOREA":"<color=#ff3636>레지나.</color>","JPN":"<color=#ff3636>レジーナ。</color>","ENG":"<color=#ff3636>Regina.</color>","TWN":"<color=#ff3636>蕾佳娜。</color>"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHASER_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};